function __ssfc(ctx) {
  const { props, slots, emit } = ctx;
  const stories = signal([
  {
    id: 'alpha',
    title: 'Web shell parity',
    host: 'web',
    hostLabel: 'Web host proof',
    status: 'Ready',
    summary: 'The shared route stays renderer-neutral while the web target keeps DOM work on the fast local path.',
    hostNote: 'Web keeps DOM-specific optimizations inside renderer-web instead of widening shared helpers.'
  },
  {
    id: 'bravo',
    title: 'Android command fidelity',
    host: 'android',
    hostLabel: 'Android host proof',
    status: 'Ready',
    summary: 'The same route module drives Android views through host commands, event payloads, and keyed mutations.',
    hostNote: 'Android stays command-oriented so JS owns reconciliation while native owns concrete view mutation.'
  },
  {
    id: 'charlie',
    title: 'iOS bridge readiness',
    host: 'ios',
    hostLabel: 'iOS host proof',
    status: 'Planned locally',
    summary: 'The shared source already reserves the iOS host surface without treating DOM output as the source of truth.',
    hostNote: 'iOS remains a thin UIKit host target, with the bridge carrying commands and event payloads only.'
  }
], { key: "stories" })

const queueVisible = signal(true, { key: "queueVisible" })
const selectedStoryId = signal('alpha', { key: "selectedStoryId" })
const hostNoteFilter = signal('', { key: "hostNoteFilter" })

function boardSummary() {
  return `${stories().length} proof slices are driven from shared source while each host target keeps its concrete view layer thin.`
}

function queueMeta() {
  return queueVisible()
    ? `${stories().length} keyed items ready`
    : 'Queue collapsed'
}

function toggleQueue() {
  queueVisible.set(!queueVisible())
}

function selectStory(id) {
  selectedStoryId.set(id)
}

function selectedStory() {
  return stories().find((story) => story.id === selectedStoryId()) || null
}

function selectedSummary() {
  const story = selectedStory()
  return story ? `${story.hostLabel} selected` : 'No proof slice selected'
}

function selectedHostNote() {
  const story = selectedStory()
  return story ? story.hostNote : ''
}

function readEventTextValue(event) {
  if (event && typeof event.value === 'string') {
    return event.value
  }

  if (event && typeof event.text === 'string') {
    return event.text
  }

  if (event && event.target && typeof event.target.value === 'string') {
    return event.target.value
  }

  return ''
}

function normalizedHostNoteFilter() {
  return hostNoteFilter().trim().toLowerCase()
}

function updateHostNoteFilter(event) {
  hostNoteFilter.set(readEventTextValue(event))
}

function hasSelectedHostNote() {
  return selectedHostNote().length > 0
}

function hostNoteFilterSummary() {
  const filter = hostNoteFilter().trim()
  return filter.length > 0
    ? `Filtering host note by "${filter}".`
    : 'Host note filter inactive.'
}

function showsSelectedHostNote() {
  const note = selectedHostNote()
  if (!note.length) {
    return false
  }

  const filter = normalizedHostNoteFilter()
  return filter.length === 0 || note.toLowerCase().includes(filter)
}

function filteredHostNoteSummary() {
  const filter = hostNoteFilter().trim()
  return filter.length > 0
    ? `Current host note is hidden until it matches "${filter}".`
    : ''
}

function promoteSelected() {
  const currentId = selectedStoryId()

  stories.update((list) => {
    const index = list.findIndex((story) => story.id === currentId)

    if (index <= 0) {
      return list
    }

    const selected = list[index]
    return [selected, ...list.slice(0, index), ...list.slice(index + 1)]
  })
}

function rotateQueue() {
  stories.update((list) => {
    if (list.length < 2) {
      return list
    }

    return [...list.slice(1), list[0]]
  })
}

function storyButtonClass(story) {
  return story.id === selectedStoryId()
    ? 'proof-state-board__story proof-state-board__story--active'
    : 'proof-state-board__story'
}
  return { stories, queueVisible, selectedStoryId, hostNoteFilter, boardSummary, queueMeta, toggleQueue, selectStory, selectedStory, selectedSummary, selectedHostNote, readEventTextValue, normalizedHostNoteFilter, updateHostNoteFilter, hasSelectedHostNote, hostNoteFilterSummary, showsSelectedHostNote, filteredHostNoteSummary, promoteSelected, rotateQueue, storyButtonClass };
}
